#include <stdio.h>
#include <stdlib.h>

// Function to swap two elements
void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

// Function to generate all permutations
void generate_permutations(int *arr, int n, int start, int end) {
    if (start == end) {
        // Print the permutation
        for (int i = 0; i < n; i++) {
            printf("%d ", arr[i]);
        }
        printf("\n");
    } else {
        for (int i = start; i <= end; i++) {
            swap(&arr[start], &arr[i]);
            generate_permutations(arr, n, start + 1, end);
            swap(&arr[start], &arr[i]); // backtrack
        }
    }
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int *arr = (int *)malloc(M * sizeof(int));
    for (int i = 0; i < M; i++) {
        arr[i] = i + 1;
    }
    generate_permutations(arr, M, 0, M - 1);
    free(arr);
    return 0;
}

