// Function to calculate the total distance
int calculate_distance(vector<vector<int>> &voters, vector<int> &permutation) {
    int total_distance = 0;
    for (int i = 0; i < voters.size(); i++) {
        for (int j = 0; j < permutation.size(); j++) {
            for (int k = j + 1; k < permutation.size(); k++) {
                if (find(voters[i].begin(), voters[i].end(), permutation[j]) > find(voters[i].begin(), voters[i].end(), permutation[k])) {
                    total_distance++;
                }
            }
        }
    }
    return total_distance;
}

int main() {
    int N, M;
    cin >> N >> M;
    vector<vector<int>> voters(N, vector<int>(M));
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            cin >> voters[i][j];
        }
    }
    vector<int> permutation(M);
    for (int i = 0; i < M; i++) {
        permutation[i] = i + 1;
    }
    int min_distance = INT_MAX;
    vector<int> min_permutation;
    do {
        int distance = calculate_distance(voters, permutation);
        if (distance < min_distance) {
            min_distance = distance;
            min_permutation = permutation;
        }
    } while (next_permutation(permutation.begin(), permutation.end()));
    cout << min_distance << ": ";
    for (int i = 0; i < min_permutation.size(); i++) {
        cout << min_permutation[i] << " ";
    }
    cout << endl;
    return 0;
}

