import java.util.Scanner;
import java.util.Arrays;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int[][] voters = new int[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                voters[i][j] = sc.nextInt();
            }
        }
        int[] permutation = new int[M];
        for (int i = 0; i < M; i++) {
            permutation[i] = i + 1;
        }
        int min_distance = Integer.MAX_VALUE;
        int[] min_permutation = new int[M];
        do {
            int distance = calculate_distance(voters, permutation);
            if (distance < min_distance) {
                min_distance = distance;
                System.arraycopy(permutation, 0, min_permutation, 0, M);
            }
        } while (next_permutation(permutation));
        System.out.println(min_distance + ": ");
        for (int i = 0; i < min_permutation.length; i++) {
            System.out.print(min_permutation[i] + " ");
        }
        System.out.println();
    }

    public static int calculate_distance(int[][] voters, int[] permutation) {
        int total_distance = 0;
        for (int i = 0; i < voters.length; i++) {
            for (int j = 0; j < permutation.length; j++) {
                for (int k = j + 1; k < permutation.length; k++) {
                    if (indexOf(voters[i], permutation[j]) > indexOf(voters[i], permutation[k])) {
                        total_distance++;
                    }
                }
            }
        }
        return total_distance;
    }

    public static int indexOf(int[] array, int value) {
        for (int i = 0; i < array.length; i++) {
            if (array[i] == value) {
                return i;
            }
        }
        return -1;
    }

    public static boolean next_permutation(int[] array) {
        int i = array.length - 2;
        while (i >= 0 && array[i] >= array[i + 1]) {
            i--;
        }
        if (i < 0) {
            return false;
        }
        int j = array.length - 1;
        while (array[j] <= array[i]) {
            j--;
        }
        swap(array, i, j);
        reverse(array, i + 1);
        return true;
    }

    public static void swap(int[] array, int i, int j) {
        int temp = array[i];
        array[i] = array[j];
        array[j] = temp;
    }

    public static void reverse(int[] array, int start) {
        int i = start;
        int j = array.length - 1;
        while (i < j) {
            swap(array, i, j);
            i++;
            j--;
        }
    }
}

