import sys
import itertools

def calculate_distance(voters, permutation):
    total_distance = 0
    for voter in voters:
        for i in range(len(permutation)):
            for j in range(i + 1, len(permutation)):
                if voter.index(permutation[i]) > voter.index(permutation[j]):
                    total_distance += 1
    return total_distance

