voters = [list(map(int, sys.stdin.readline().split())) for _ in range(N)]
permutation = list(range(1, M + 1))
min_distance = float('inf')
min_permutation = None
for p in itertools.permutations(permutation):
    distance = calculate_distance(voters, p)
    if distance < min_distance:
        min_distance = distance
        min_permutation = p
print(f'{min_distance}: {" ".join(map(str, min_permutation))}')

