const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function calculate_distance(voters, permutation) {
    let total_distance = 0;
    for (let i = 0; i < voters.length; i++) {
        for (let j = 0; j < permutation.length; j++) {
            for (let k = j + 1; k < permutation.length; k++) {
                if (voters[i].indexOf(permutation[j]) > voters[i].indexOf(permutation[k])) {
                    total_distance++;
                }
            }
        }
    }
    return total_distance;
}

function next_permutation(array) {
    let i = array.length - 2;
    while (i >= 0 && array[i] >= array[i + 1]) {
        i--;
    }
    if (i < 0) {
        return false;
    }
    let j = array.length - 1;
    while (array[j] <= array[i]) {
        j--;
    }
    [array[i], array[j]] = [array[j], array[i]];
    array.splice(i + 1, array.length - i - 1, ...array.slice(i + 1).reverse());
    return true;
}

let N, M;
[N, M] = lines[idx++].split(' ').map(Number);
let voters = [];
for (let i = 0; i < N; i++) {
    voters.push(lines[idx++].split(' ').map(Number));
}
let permutation = Array.from({ length: M }, (_, i) => i + 1);
let min_distance = Infinity;
let min_permutation;
let permutations = [];
let used = {};
function generate_permutations(arr, m = []) {
    if (arr.length === 0) {
        permutations.push(m);
    } else {
        for (let i = 0; i < arr.length; i++) {
            let curr = arr.slice();
            let test = curr.splice(i, 1);
            if (!used[test]) {
                used[test] = true;
                generate_permutations(curr.slice(), m.concat(test));
            }
        }
    }
}

generate_permutations(permutation);
for (let p of permutations) {
    let distance = calculate_distance(voters, p);
    if (distance < min_distance) {
        min_distance = distance;
        min_permutation = p;
    }
}
